// CSV Parser Library for TypeScript

interface ParseOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

interface ParseError {
  row: number;
  message: string;
}

class CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: ParseError[];

  constructor(rows: Record<string, any>[], headers: string[], errors: ParseError[]) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  filter(predicate: (row: Record<string, any>) => boolean): Record<string, any>[] {
    return this.rows.filter(predicate);
  }

  sum(column: string): number {
    return this.rows.reduce((sum, row) => {
      const value = row[column];
      if (typeof value === 'number') {
        return sum + value;
      }
      return sum;
    }, 0);
  }

  average(column: string): number {
    const numbers = this.rows
      .map(row => row[column])
      .filter(val => typeof val === 'number');

    if (numbers.length === 0) return 0;
    return numbers.reduce((a, b) => a + b, 0) / numbers.length;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<any, Record<string, any>[]> {
    const map = new Map<any, Record<string, any>[]>();

    for (const row of this.rows) {
      const key = row[column];
      if (!map.has(key)) {
        map.set(key, []);
      }
      map.get(key)!.push(row);
    }

    return map;
  }
}

function coerceType(value: string): any {
  // Handle null/empty
  if (value === '' || value.toLowerCase() === 'null') {
    return null;
  }

  // Handle booleans
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Handle numbers
  if (!isNaN(Number(value)) && value.trim() !== '') {
    return Number(value);
  }

  // Everything else is a string
  return value;
}

interface ParseRowResult {
  fields: string[];
}

function parseRow(
  line: string,
  delimiter: string,
  quoteChar: string
): ParseRowResult | null {
  const fields: string[] = [];
  let current = '';
  let insideQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    if (char === quoteChar) {
      // Check if it's an escaped quote (two quotes in a row)
      if (i + 1 < line.length && line[i + 1] === quoteChar) {
        // Escaped quote
        current += quoteChar;
        i += 2;
      } else {
        // Toggle quote state
        insideQuotes = !insideQuotes;
        i++;
      }
    } else if (char === delimiter && !insideQuotes) {
      // Field separator
      fields.push(current);
      current = '';
      i++;
    } else {
      // Regular character
      current += char;
      i++;
    }
  }

  // Add the last field
  fields.push(current);

  // Check if we're still inside quotes (unclosed)
  if (insideQuotes) {
    return null; // Malformed
  }

  return { fields };
}

function parseCSV(input: string, options?: ParseOptions): CSVResult {
  const delimiter = options?.delimiter ?? ',';
  const quoteChar = options?.quoteChar ?? '"';
  const lineSeparator = options?.lineSeparator ?? '\n';

  const errors: ParseError[] = [];
  const lines = input.split(lineSeparator).filter(line => line.trim() !== '');

  if (lines.length === 0) {
    return new CSVResult([], [], errors);
  }

  // Parse header
  const headerFields = parseRow(lines[0], delimiter, quoteChar);
  if (!headerFields) {
    errors.push({ row: 1, message: 'Failed to parse header row' });
    return new CSVResult([], [], errors);
  }

  const headers = headerFields.fields;

  // Parse data rows
  const rows: Record<string, any>[] = [];

  for (let i = 1; i < lines.length; i++) {
    const result = parseRow(lines[i], delimiter, quoteChar);

    if (!result) {
      errors.push({ row: i + 1, message: 'Malformed row: failed to parse' });
      continue;
    }

    const { fields } = result;

    // Check if field count matches header count
    if (fields.length !== headers.length) {
      errors.push({
        row: i + 1,
        message: `Column count mismatch: expected ${headers.length}, got ${fields.length}`,
      });
      continue;
    }

    // Create object from fields
    const row: Record<string, any> = {};
    for (let j = 0; j < headers.length; j++) {
      row[headers[j]] = coerceType(fields[j]);
    }

    rows.push(row);
  }

  return new CSVResult(rows, headers, errors);
}

export { parseCSV, CSVResult, ParseOptions, ParseError };

import { parseCSV, CSVResult } from './csv-parser';

// Simple assertion helpers
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`❌ Assertion failed: ${message}`);
  }
}

function assertEqual<T>(
  actual: T,
  expected: T,
  message: string = ''
): void {
  const actualStr = JSON.stringify(actual);
  const expectedStr = JSON.stringify(expected);

  if (actualStr !== expectedStr) {
    throw new Error(
      `❌ Assertion failed: ${message}\n  Expected: ${expectedStr}\n  Actual: ${actualStr}`
    );
  }
}

function assertIncludes(text: string, substring: string, message: string): void {
  if (!text.includes(substring)) {
    throw new Error(
      `❌ Assertion failed: ${message}\n  String "${text}" does not include "${substring}"`
    );
  }
}

// Test 1: Basic parsing
function testBasicParsing(): void {
  const input = `name,age,city
John,30,New York
Jane,25,Los Angeles`;

  const result = parseCSV(input);

  assertEqual(result.headers, ['name', 'age', 'city'], 'Headers should match');
  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertEqual(result.rows[0].name, 'John', 'First row name should be John');
  assertEqual(result.rows[1].name, 'Jane', 'Second row name should be Jane');

  console.log('✓ testBasicParsing passed');
}

// Test 2: Quoted fields with commas
function testQuotedFieldsWithCommas(): void {
  const input = `name,address
John,"123 Main St, Suite 100"
Jane,"456 Oak Ave, Apt 5"`;

  const result = parseCSV(input);

  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertEqual(
    result.rows[0].address,
    '123 Main St, Suite 100',
    'Address with comma should be parsed correctly'
  );
  assertEqual(
    result.rows[1].address,
    '456 Oak Ave, Apt 5',
    'Second address should be parsed correctly'
  );

  console.log('✓ testQuotedFieldsWithCommas passed');
}

// Test 3: Escaped quotes
function testEscapedQuotes(): void {
  const input = `name,description
John,"He said ""Hello"""
Jane,"She said ""Hi"""`;

  const result = parseCSV(input);

  assertEqual(
    result.rows[0].description,
    'He said "Hello"',
    'Escaped quotes should be handled'
  );
  assertEqual(
    result.rows[1].description,
    'She said "Hi"',
    'Second escaped quotes should be handled'
  );

  console.log('✓ testEscapedQuotes passed');
}

// Test 4: Custom delimiters
function testCustomDelimiter(): void {
  const input = `name;age;city
John;30;New York
Jane;25;Los Angeles`;

  const result = parseCSV(input, { delimiter: ';' });

  assertEqual(result.headers, ['name', 'age', 'city'], 'Custom delimiter should work');
  assertEqual(result.rows[0].age, 30, 'Age should be parsed with custom delimiter');

  console.log('✓ testCustomDelimiter passed');
}

// Test 5: Type coercion - integers
function testTypeCoercionIntegers(): void {
  const input = `name,age
John,30
Jane,25`;

  const result = parseCSV(input);

  assertEqual(typeof result.rows[0].age, 'number', 'Age should be number');
  assertEqual(result.rows[0].age, 30, 'Age value should be 30');
  assertEqual(result.rows[1].age, 25, 'Age value should be 25');

  console.log('✓ testTypeCoercionIntegers passed');
}

// Test 6: Type coercion - floats
function testTypeCoercionFloats(): void {
  const input = `name,score,gpa
John,95.5,3.75
Jane,87.3,3.92`;

  const result = parseCSV(input);

  assertEqual(typeof result.rows[0].score, 'number', 'Score should be number');
  assertEqual(result.rows[0].score, 95.5, 'Score value should be 95.5');
  assertEqual(result.rows[1].gpa, 3.92, 'GPA value should be 3.92');

  console.log('✓ testTypeCoercionFloats passed');
}

// Test 7: Type coercion - booleans (case insensitive)
function testTypeCoercionBooleans(): void {
  const input = `name,active,verified
John,true,FALSE
Jane,TRUE,false`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].active, true, 'true should be boolean true');
  assertEqual(result.rows[0].verified, false, 'FALSE should be boolean false');
  assertEqual(result.rows[1].active, true, 'TRUE should be boolean true');
  assertEqual(result.rows[1].verified, false, 'false should be boolean false');

  console.log('✓ testTypeCoercionBooleans passed');
}

// Test 8: Type coercion - nulls
function testTypeCoercionNulls(): void {
  const input = `name,nickname,alias
John,null,
Jane,,NULL`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].nickname, null, '"null" should be null');
  assertEqual(result.rows[0].alias, null, 'Empty string should be null');
  assertEqual(result.rows[1].nickname, null, 'Empty string should be null');
  assertEqual(result.rows[1].alias, null, '"NULL" should be null');

  console.log('✓ testTypeCoercionNulls passed');
}

// Test 9: Type coercion - strings (non-numeric)
function testTypeCoercionStrings(): void {
  const input = `name,city
John,New York
Jane,Los Angeles`;

  const result = parseCSV(input);

  assertEqual(typeof result.rows[0].name, 'string', 'Name should be string');
  assertEqual(typeof result.rows[0].city, 'string', 'City should be string');

  console.log('✓ testTypeCoercionStrings passed');
}

// Test 10: Malformed row - unclosed quotes
function testMalformedRowUnclosedQuotes(): void {
  const input = `name,age
John,30
"Unclosed quote,25
Jane,25`;

  const result = parseCSV(input);

  assertEqual(result.errors.length, 1, 'Should have 1 error');
  assertEqual(result.errors[0].row, 2, 'Error should be on row 2');
  assertIncludes(
    result.errors[0].message,
    'Malformed',
    'Error message should indicate malformed row'
  );
  assertEqual(result.rows.length, 2, 'Should still parse valid rows');

  console.log('✓ testMalformedRowUnclosedQuotes passed');
}

// Test 11: Column count mismatch error
function testColumnCountMismatch(): void {
  const input = `name,age,city
John,30
Jane,25,Los Angeles`;

  const result = parseCSV(input);

  assertEqual(result.errors.length, 1, 'Should have 1 error');
  assertEqual(result.errors[0].row, 2, 'Error should be on row 2 (0-indexed + 1)');
  assertIncludes(
    result.errors[0].message,
    'Column count mismatch',
    'Error should mention column count mismatch'
  );
  assertEqual(result.rows.length, 1, 'Should only have 1 valid row');

  console.log('✓ testColumnCountMismatch passed');
}

// Test 12: Filter functionality
function testFilter(): void {
  const input = `name,age,city
John,30,New York
Jane,25,Los Angeles
Bob,35,Chicago`;

  const result = parseCSV(input);
  const filtered = result.filter(row => row.age >= 30);

  assertEqual(filtered.length, 2, 'Should have 2 rows with age >= 30');
  assertEqual(filtered[0].name, 'John', 'First filtered row should be John');
  assertEqual(filtered[1].name, 'Bob', 'Second filtered row should be Bob');

  console.log('✓ testFilter passed');
}

// Test 13: Filter with string comparison
function testFilterStringComparison(): void {
  const input = `name,department
John,Engineering
Jane,Marketing
Bob,Engineering`;

  const result = parseCSV(input);
  const filtered = result.filter(row => row.department === 'Engineering');

  assertEqual(filtered.length, 2, 'Should have 2 Engineering rows');

  console.log('✓ testFilterStringComparison passed');
}

// Test 14: Sum aggregation
function testSum(): void {
  const input = `name,salary
John,50000
Jane,45000
Bob,60000`;

  const result = parseCSV(input);
  const total = result.sum('salary');

  assertEqual(total, 155000, 'Sum should be 155000');

  console.log('✓ testSum passed');
}

// Test 15: Sum with non-numeric values
function testSumNonNumeric(): void {
  const input = `name,value
John,100
Jane,not a number
Bob,50`;

  const result = parseCSV(input);
  const total = result.sum('value');

  assertEqual(total, 150, 'Sum should ignore non-numeric values');

  console.log('✓ testSumNonNumeric passed');
}

// Test 16: Average aggregation
function testAverage(): void {
  const input = `name,score
John,90
Jane,80
Bob,100`;

  const result = parseCSV(input);
  const avg = result.average('score');

  assertEqual(avg, 90, 'Average should be 90');

  console.log('✓ testAverage passed');
}

// Test 17: Average with non-numeric values
function testAverageNonNumeric(): void {
  const input = `name,value
John,100
Jane,not a number
Bob,50`;

  const result = parseCSV(input);
  const avg = result.average('value');

  assertEqual(avg, 75, 'Average should only include numeric values: (100 + 50) / 2 = 75');

  console.log('✓ testAverageNonNumeric passed');
}

// Test 18: Count aggregation
function testCount(): void {
  const input = `name,age
John,30
Jane,25
Bob,35`;

  const result = parseCSV(input);

  assertEqual(result.count(), 3, 'Count should be 3');

  console.log('✓ testCount passed');
}

// Test 19: GroupBy aggregation
function testGroupBy(): void {
  const input = `name,department,salary
John,Engineering,50000
Jane,Marketing,45000
Bob,Engineering,60000`;

  const result = parseCSV(input);
  const grouped = result.groupBy('department');

  assertEqual(grouped.size, 2, 'Should have 2 groups');
  assertEqual(grouped.get('Engineering')!.length, 2, 'Engineering group should have 2 rows');
  assertEqual(grouped.get('Marketing')!.length, 1, 'Marketing group should have 1 row');
  assertEqual(grouped.get('Engineering')![0].name, 'John', 'First Engineering row should be John');

  console.log('✓ testGroupBy passed');
}

// Test 20: GroupBy with null values
function testGroupByWithNulls(): void {
  const input = `name,category
John,A
Jane,
Bob,A`;

  const result = parseCSV(input);
  const grouped = result.groupBy('category');

  assertEqual(grouped.size, 2, 'Should have 2 groups (A and null)');
  assertEqual(grouped.get('A')!.length, 2, 'Category A should have 2 rows');
  assertEqual(grouped.get(null)!.length, 1, 'Null category should have 1 row');

  console.log('✓ testGroupByWithNulls passed');
}

// Test 21: Empty input
function testEmptyInput(): void {
  const result = parseCSV('');

  assertEqual(result.rows.length, 0, 'Should have 0 rows');
  assertEqual(result.headers.length, 0, 'Should have 0 headers');
  assertEqual(result.errors.length, 0, 'Should have 0 errors');

  console.log('✓ testEmptyInput passed');
}

// Test 22: Single column
function testSingleColumn(): void {
  const input = `name
John
Jane
Bob`;

  const result = parseCSV(input);

  assertEqual(result.headers.length, 1, 'Should have 1 header');
  assertEqual(result.headers[0], 'name', 'Header should be "name"');
  assertEqual(result.rows.length, 3, 'Should have 3 rows');
  assertEqual(result.rows[0].name, 'John', 'First row should be John');

  console.log('✓ testSingleColumn passed');
}

// Test 23: Single row (just header)
function testSingleRowData(): void {
  const input = `name,age
John,30`;

  const result = parseCSV(input);

  assertEqual(result.rows.length, 1, 'Should have 1 row');
  assertEqual(result.rows[0].name, 'John', 'Row name should be John');
  assertEqual(result.rows[0].age, 30, 'Row age should be 30');

  console.log('✓ testSingleRowData passed');
}

// Test 24: Just header, no data
function testHeaderOnly(): void {
  const input = `name,age,city`;

  const result = parseCSV(input);

  assertEqual(result.headers.length, 3, 'Should have 3 headers');
  assertEqual(result.rows.length, 0, 'Should have 0 rows');

  console.log('✓ testHeaderOnly passed');
}

// Test 25: Very large fields
function testVeryLargeFields(): void {
  const longText = 'a'.repeat(10000);
  const input = `name,description
John,"${longText}"
Jane,short`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].description.length, 10000, 'Large field should be parsed');
  assertEqual(result.rows[1].description, 'short', 'Short field should work');

  console.log('✓ testVeryLargeFields passed');
}

// Test 26: Quoted fields at start and end
function testQuotedFieldsEdges(): void {
  const input = `name,age,city
"John",30,"New York"
Jane,25,"Los Angeles"`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].name, 'John', 'Quoted name should work');
  assertEqual(result.rows[0].city, 'New York', 'Quoted city should work');
  assertEqual(result.rows[1].name, 'Jane', 'Unquoted name should work');

  console.log('✓ testQuotedFieldsEdges passed');
}

// Test 27: Mixed data types in same column
function testMixedTypesInColumn(): void {
  const input = `name,value
John,123
Jane,hello
Bob,true
Alice,null`;

  const result = parseCSV(input);

  assertEqual(typeof result.rows[0].value, 'number', 'First value should be number');
  assertEqual(result.rows[0].value, 123, 'First value should be 123');
  assertEqual(typeof result.rows[1].value, 'string', 'Second value should be string');
  assertEqual(result.rows[1].value, 'hello', 'Second value should be "hello"');
  assertEqual(typeof result.rows[2].value, 'boolean', 'Third value should be boolean');
  assertEqual(result.rows[3].value, null, 'Fourth value should be null');

  console.log('✓ testMixedTypesInColumn passed');
}

// Test 28: Tab delimiter
function testTabDelimiter(): void {
  const input = `name\tage\tcity
John\t30\tNew York
Jane\t25\tLos Angeles`;

  const result = parseCSV(input, { delimiter: '\t' });

  assertEqual(result.headers, ['name', 'age', 'city'], 'Tab delimiter should work');
  assertEqual(result.rows[0].name, 'John', 'First row name should be John');

  console.log('✓ testTabDelimiter passed');
}

// Test 29: Pipe delimiter with quoted fields
function testPipeDelimiter(): void {
  const input = `name|description
John|"Contains | pipe"
Jane|Normal text`;

  const result = parseCSV(input, { delimiter: '|' });

  assertEqual(result.rows[0].description, 'Contains | pipe', 'Pipe inside quotes should be preserved');
  assertEqual(result.rows[1].description, 'Normal text', 'Normal field should work');

  console.log('✓ testPipeDelimiter passed');
}

// Test 30: Multiple consecutive quoted fields
function testMultipleQuotedFields(): void {
  const input = `col1,col2,col3
"value1","value2","value3"
"a","b","c"`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].col1, 'value1', 'First quoted field');
  assertEqual(result.rows[0].col2, 'value2', 'Second quoted field');
  assertEqual(result.rows[0].col3, 'value3', 'Third quoted field');

  console.log('✓ testMultipleQuotedFields passed');
}

// Test 31: Quotes in middle of field
function testQuotesInMiddleOfField(): void {
  const input = `name,description
John,He said "hello" to me`;

  const result = parseCSV(input);

  assertEqual(
    result.rows[0].description,
    'He said "hello" to me',
    'Quotes in middle of unquoted field should be literal'
  );

  console.log('✓ testQuotesInMiddleOfField passed');
}

// Test 32: Newlines in quoted fields (note: our implementation splits by newline)
function testWhitespaceHandling(): void {
  const input = `name,age
  John  ,  30  
Jane,25`;

  const result = parseCSV(input);

  // Note: whitespace is preserved in our implementation
  assertEqual(result.rows.length, 2, 'Should have 2 rows');

  console.log('✓ testWhitespaceHandling passed');
}

// Test 33: Numbers with leading zeros
function testNumbersWithLeadingZeros(): void {
  const input = `name,code
John,00123
Jane,99999`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].code, 123, 'Leading zeros should be stripped in number conversion');
  assertEqual(result.rows[1].code, 99999, 'Regular numbers should work');

  console.log('✓ testNumbersWithLeadingZeros passed');
}

// Test 34: Negative numbers
function testNegativeNumbers(): void {
  const input = `name,balance
John,-100.50
Jane,200.75`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].balance, -100.5, 'Negative numbers should be parsed');
  assertEqual(result.rows[1].balance, 200.75, 'Positive numbers should work');

  console.log('✓ testNegativeNumbers passed');
}

// Test 35: Scientific notation
function testScientificNotation(): void {
  const input = `name,value
John,1e5
Jane,2.5e-3`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].value, 100000, 'Scientific notation should be parsed: 1e5 = 100000');
  assertEqual(result.rows[1].value, 0.0025, 'Scientific notation should work: 2.5e-3 = 0.0025');

  console.log('✓ testScientificNotation passed');
}

// Test 36: Filter chaining
function testFilterReturnsArray(): void {
  const input = `name,age
John,30
Jane,25
Bob,35`;

  const result = parseCSV(input);
  const filtered = result.filter(row => row.age > 25);

  // Verify it returns a plain array
  assert(Array.isArray(filtered), 'filter() should return an array');
  assertEqual(filtered.length, 2, 'Filtered array should have 2 elements');

  console.log('✓ testFilterReturnsArray passed');
}

// Test 37: Empty quoted field
function testEmptyQuotedField(): void {
  const input = `name,nickname,age
John,"",30
Jane,JD,25`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].nickname, null, 'Empty quoted field should be null');
  assertEqual(result.rows[1].nickname, 'JD', 'Regular field should work');

  console.log('✓ testEmptyQuotedField passed');
}

// Test 38: Only commas
function testOnlyCommas(): void {
  const input = `a,b,c
,,"`;

  const result = parseCSV(input);

  // Empty string at end is not quoted so it's treated as empty which becomes null
  // But the last quote is problematic
  // Actually the last quote will cause unclosed quote error
  assertEqual(result.errors.length, 1, 'Should have error for unclosed quote');

  console.log('✓ testOnlyCommas passed');
}

// Test 39: Consecutive delimiters
function testConsecutiveDelimiters(): void {
  const input = `a,b,c
1,,3
,2,`;

  const result = parseCSV(input);

  assertEqual(result.rows[0].b, null, 'Empty field should be null');
  assertEqual(result.rows[1].a, null, 'Empty field at start should be null');
  assertEqual(result.rows[1].c, null, 'Empty field at end should be null');

  console.log('✓ testConsecutiveDelimiters passed');
}

// Test 40: Multiple errors collected
function testMultipleErrors(): void {
  const input = `name,age,city
"unclosed
Jane,25
Bob,30,New York,Extra`;

  const result = parseCSV(input);

  assertEqual(result.errors.length, 2, 'Should have 2 errors');
  assertEqual(result.rows.length, 0, 'Should have 0 valid rows (all rows have errors)');

  console.log('✓ testMultipleErrors passed');
}

// Run all tests
function runAllTests(): void {
  console.log('🧪 Running CSV Parser Test Suite...\n');

  const tests = [
    testBasicParsing,
    testQuotedFieldsWithCommas,
    testEscapedQuotes,
    testCustomDelimiter,
    testTypeCoercionIntegers,
    testTypeCoercionFloats,
    testTypeCoercionBooleans,
    testTypeCoercionNulls,
    testTypeCoercionStrings,
    testMalformedRowUnclosedQuotes,
    testColumnCountMismatch,
    testFilter,
    testFilterStringComparison,
    testSum,
    testSumNonNumeric,
    testAverage,
    testAverageNonNumeric,
    testCount,
    testGroupBy,
    testGroupByWithNulls,
    testEmptyInput,
    testSingleColumn,
    testSingleRowData,
    testHeaderOnly,
    testVeryLargeFields,
    testQuotedFieldsEdges,
    testMixedTypesInColumn,
    testTabDelimiter,
    testPipeDelimiter,
    testMultipleQuotedFields,
    testQuotesInMiddleOfField,
    testWhitespaceHandling,
    testNumbersWithLeadingZeros,
    testNegativeNumbers,
    testScientificNotation,
    testFilterReturnsArray,
    testEmptyQuotedField,
    testOnlyCommas,
    testConsecutiveDelimiters,
    testMultipleErrors,
  ];

  let passed = 0;
  let failed = 0;

  for (const test of tests) {
    try {
      test();
      passed++;
    } catch (error) {
      console.error(`\n${error instanceof Error ? error.message : String(error)}`);
      failed++;
    }
  }

  console.log(`\n${'='.repeat(50)}`);
  console.log(`Tests passed: ${passed}/${tests.length}`);
