const { parseCSV } = require('./csv-parser');

// Simple assertion helpers
function assert(condition, message) {
  if (!condition) {
    throw new Error(`❌ Assertion failed: ${message}`);
  }
}

function assertEqual(actual, expected, message = '') {
  const actualStr = JSON.stringify(actual);
  const expectedStr = JSON.stringify(expected);

  if (actualStr !== expectedStr) {
    throw new Error(
      `❌ Assertion failed: ${message}\n  Expected: ${expectedStr}\n  Actual: ${actualStr}`
    );
  }
}

function assertIncludes(text, substring, message) {
  if (!text.includes(substring)) {
    throw new Error(
      `❌ Assertion failed: ${message}\n  String "${text}" does not include "${substring}"`
    );
  }
}

// Test 1: Basic parsing
function testBasicParsing() {
  const input = `name,age,city
John,30,New York
Jane,25,Los Angeles`;

  const result = parseCSV(input);

  assertEqual(result.headers, ['name', 'age', 'city'], 'Headers should match');
  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertEqual(result.rows[0].name, 'John', 'First row name should be John');
  assertEqual(result.rows[1].name, 'Jane', 'Second row name should be Jane');

