// Simple assertion helpers
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`❌ Assertion failed: ${message}`);
  }
}

function assertEqual<T>(
  actual: T,
  expected: T,
  message: string = ''
): void {
  const actualStr = JSON.stringify(actual);
  const expectedStr = JSON.stringify(expected);

  if (actualStr !== expectedStr) {
    throw new Error(
      `❌ Assertion failed: ${message}\n  Expected: ${expectedStr}\n  Actual: ${actualStr}`
    );
  }
}

function assertIncludes(text: string, substring: string, message: string): void {
  if (!text.includes(substring)) {
    throw new Error(
      `❌ Assertion failed: ${message}\n  String "${text}" does not include "${substring}"`
    );
  }
}

