  const tests = [
    testBasicParsing,
    testQuotedFieldsWithCommas,
    testEscapedQuotes,
    testCustomDelimiter,
    testTypeCoercionIntegers,
    testTypeCoercionFloats,
    testTypeCoercionBooleans,
    testTypeCoercionNulls,
    testTypeCoercionStrings,
    testMalformedRowUnclosedQuotes,
    testColumnCountMismatch,
    testFilter,
    testFilterStringComparison,
    testSum,
    testSumNonNumeric,
    testAverage,
    testAverageNonNumeric,
    testCount,
    testGroupBy,
    testGroupByWithNulls,
    testEmptyInput,
    testSingleColumn,
    testSingleRowData,
    testHeaderOnly,
    testVeryLargeFields,
    testQuotedFieldsEdges,
    testMixedTypesInColumn,
    testTabDelimiter,
    testPipeDelimiter,
    testMultipleQuotedFields,
    testQuotesInMiddleOfField,
    testWhitespaceHandling,
    testNumbersWithLeadingZeros,
    testNegativeNumbers,
    testScientificNotation,
    testFilterReturnsArray,
    testEmptyQuotedField,
    testOnlyCommas,
    testConsecutiveDelimiters,
    testMultipleErrors,
  ];

  let passed = 0;
  let failed = 0;

  for (const test of tests) {
    try {
      test();
      passed++;
    } catch (error) {
      console.error(`\n${error instanceof Error ? error.message : String(error)}`);
      failed++;
    }
  }

  console.log(`\n${'='.repeat(50)}`);
  console.log(`Tests passed: ${passed}/${tests.length}`);
  console.log(`Tests failed: ${failed}/${tests.length}`);
  console.log(`${'='.repeat(50)}`);

  if (failed === 0) {
    console.log('\n🎉 All tests passed!');
  } else {
    process.exit(1);
  }
}

// Run tests
runAllTests();

